from typing import Callable

@dataclass
class SelfAssessmentCheck:
    check_id: str
    description: str
    automated: bool           # True if verifiable by a script
    verify_fn: Callable[[], bool] | None = None  # set when automated=True

class SelfAssessmentRunner:
    """
    Runs automated checks and records manual attestations to produce
    a self-assessment score the risk steward reviews before fieldwork.
    """
    def __init__(self, playbook: ControlAuditPlaybook,
                 checks: list[SelfAssessmentCheck]):
        self._playbook = playbook
        self._checks = checks

    def run(self) -> dict:
        results = {}
        for check in self._checks:
            if check.automated and check.verify_fn:
                try:
                    passed = check.verify_fn()
                except Exception as exc:
                    passed = False
                    print(f"[WARN] Check {check.check_id} raised: {exc}")
            else:
                # Manual: default to None — owner must attest explicitly
                passed = None
            results[check.check_id] = {
                "description": check.description,
                "automated": check.automated,
                "passed": passed,
            }

        auto_pass  = all(v["passed"] for v in results.values() if v["automated"])
        manual_gap = any(v["passed"] is None for v in results.values() if not v["automated"])

        self._playbook.self_assessment_passed = auto_pass and not manual_gap
        return results

def run_readiness_sprint(
    playbooks: list[ControlAuditPlaybook],
    audit_period_start,
    audit_period_end,
    builder,
    required_controls: list[str],
) -> dict:
    """
    T-30 readiness sprint: returns a summary of gaps across all playbooks.
    """
    coverage = builder.coverage_report(audit_period_start, audit_period_end,
                                        required_controls)
    gaps = []
    not_ready = []

    for playbook in playbooks:
        ctrl_coverage = coverage.get(playbook.control_id, {})
        if not ctrl_coverage.get("covered"):
            gaps.append({
                "control_id": playbook.control_id,
                "owner": playbook.owner,
                "issue": "No evidence records in audit period",
            })
        if not playbook.is_ready():
            not_ready.append({
                "control_id":    playbook.control_id,
                "owner":         playbook.owner,
                "self_assessed": playbook.self_assessment_passed,
                "open_pbcs":     playbook.open_pbc_count(),
                "status":        playbook.status.value,
            })

    return {
        "evidence_gaps":      gaps,
        "not_ready_controls": not_ready,
        "ready_count": sum(1 for p in playbooks if p.is_ready()),
        "total_count":  len(playbooks),
    }

@dataclass
class ManagementResponse:
    finding_id: str
    control_id: str
    owner: str
    root_cause: str
    remediation_steps: list[str]
    target_completion: date
    compensating_controls: list[str]   # interim controls while remediation is in progress

    def validate(self) -> list[str]:
        """Returns list of validation errors; empty list means response is complete."""
        errors = []
        if not self.root_cause.strip():
            errors.append("root_cause must not be empty")
        if not self.remediation_steps:
            errors.append("at least one remediation step required")
        if self.target_completion <= date.today():
            errors.append("target_completion must be a future date")
        return errors
